static void assign_u16 (u16* dst, u16 src) {
    *dst = src;
}

static void assign_list_unit (ConfigListUnit* dst, ConfigListUnit src) {
    dst->n = src.n;
    for (u16 i = 0; i < MAX_CONFIG_LIST_ITEMS; ++i) {
        dst->keys[i] = src.keys[i];
    }
}

static void trim_ws_idx (StringManager& sm, u32 idx) {
    sm.trim_head_char(idx, ' ');
    sm.trim_tail_char(idx, ' ');
    sm.trim_head_char(idx, '\t');
    sm.trim_tail_char(idx, '\t');
    sm.trim_head_char(idx, '\r');
    sm.trim_tail_char(idx, '\r');
    sm.trim_head_char(idx, '\n');
    sm.trim_tail_char(idx, '\n');
}

static void trim_ws_all (StringManager& sm) {
    for (u32 i = 0; i < sm.get_string_count(); ++i) {
        trim_ws_idx(sm, i);
    }
}

static bool is_blank (cstr s) {
    if (s == nullptr) {
        return true;
    }
    StringManager m;
    m.load_cstr_content(s);
    trim_ws_idx(m, 0);
    return m.get_string_content(0)[0] == '\0';
}

static bool split_key_val (cstr line, StringManager& key, StringManager& val) {
    if (line == nullptr) {
        return false;
    }
    const char* sep = std::strstr(line, "==");
    if (sep == nullptr) {
        return false;
    }
    const u32 key_len = static_cast<u32>(sep - line);
    char* key_buf = new char[key_len + 1];
    std::memcpy(key_buf, line, key_len);
    key_buf[key_len] = '\0';
    key.load_cstr_content(key_buf);
    delete[] key_buf;
    val.load_cstr_content(sep + 2);
    trim_ws_idx(key, 0);
    trim_ws_idx(val, 0);
    return key.get_string_content(0)[0] != '\0';
}

static bool parse_u16 (cstr val, u16* out) {
    if (val == nullptr || out == nullptr) {
        return false;
    }
    StringManager m;
    m.load_cstr_content(val);
    trim_ws_idx(m, 0);
    val = m.get_string_content(0);
    if (val[0] == '\0') {
        return false;
    }
    char* end = nullptr;
    const unsigned long n = std::strtoul(val, &end, 10);
    if (end == val || (end != nullptr && *end != '\0')) {
        return false;
    }
    if (n > 65535ul) {
        return false;
    }
    assign_u16(out, static_cast<u16>(n));
    return true;
}

static bool parse_list_unit (cstr val, ConfigListUnit* out, u16 (*name_to_idx)(cstr)) {
    if (out == nullptr || name_to_idx == nullptr || val == nullptr) {
        return false;
    }
    ConfigListUnit tmp = {};
    StringManager items;
    items.load_cstr_content(val);
    items.split_string_by_char(0, ',');
    trim_ws_all(items);
    items.cull_empty_strings();
    tmp.n = 0;
    for (u32 i = 0; i < items.get_string_count(); ++i) {
        cstr tok = items.get_string_content(i);
        if (tmp.n >= MAX_CONFIG_LIST_ITEMS) {
            std::printf("ERROR: config list exceeds MAX_CONFIG_LIST_ITEMS: '%s'\n", val);
            return false;
        }
        const u16 idx = name_to_idx(tok);
        if (idx == U16_KEY_NULL) {
            std::printf("ERROR: config could not resolve unit '%s'\n", tok);
            return false;
        }
        tmp.keys[tmp.n] = UnitStaticDataKey::from_raw(idx);
        tmp.n = static_cast<u16>(tmp.n + 1);
    }
    if (tmp.n == 0) {
        std::printf("ERROR: config could not parse unit list: '%s'\n", val);
        return false;
    }
    assign_list_unit(out, tmp);
    return true;
}

